{"content": """"Mini calculator CLI."""
import argparse
import sys

def format_num(n):
    if n == int(n):
        return str(int(n))
    return str(n)

def main():
    parser = argparse.ArgumentParser(description="Mini calculator CLI")
    subparsers = parser.add_subparsers(dest="command", required=True)

    # Common parser for binary operations
    def add_args(sub):
        sub.add_argument("a", type=float)
        sub.add_argument("b", type=float)

    add_parser = subparsers.add_parser("add")
    add_args(add_parser)

    sub_parser = subparsers.add_parser("sub")
    add_args(sub_parser)

    mul_parser = subparsers.add_parser("mul")
    add_args(mul_parser)

    div_parser = subparsers.add_parser("div")
    add_args(div_parser)

    args = parser.parse_args()

    if args.command == "add":
        print(format_num(args.a + args.b))
    elif args.command == "sub":
        print(format_num(args.a - args.b))
    elif args.command == "mul":
        print(format_num(args.a * args.b))
    elif args.command == "div":
        if args.b == 0:
            print("Error: Division by zero", file=sys.stderr)
            sys.exit(1)
        print(format_num(args.a / args.b))

if __name__ == "__main__":
    main()
